namespace sv_2a65d08cb8f64e1bb42a2564d6d4fb77.Client;

public sealed class UserInfo
{
    public required string Email { get; init; }
    public required string[] Roles { get; init; }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_2a65d08cb8f64e1bb42a2564d6d4fb77.Client;

/// <summary>
/// Reads the persisted user info that was serialized by the server during
/// static/server rendering and re-creates the ClaimsPrincipal on the
/// WebAssembly client so auth state survives the render-mode transition.
/// </summary>
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authState;

    public PersistentAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (persistentState.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo) && userInfo is not null)
        {
            _authState = Task.FromResult(new AuthenticationState(CreatePrincipal(userInfo)));
        }
        else
        {
            _authState = _unauthenticated;
        }
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authState;

    private static ClaimsPrincipal CreatePrincipal(UserInfo user)
    {
        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, user.Email),
            new(ClaimTypes.Email, user.Email),
        };

        foreach (var role in user.Roles)
        {
            claims.Add(new Claim(ClaimTypes.Role, role));
        }

        return new ClaimsPrincipal(new ClaimsIdentity(claims, authenticationType: "PersistentAuth"));
    }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Server;
using Microsoft.AspNetCore.Components.Web;
using sv_2a65d08cb8f64e1bb42a2564d6d4fb77.Client;

namespace sv_2a65d08cb8f64e1bb42a2564d6d4fb77.Auth;

/// <summary>
/// Server-side AuthenticationStateProvider that returns a hardcoded user and
/// persists the user info into PersistentComponentState so the WASM client
/// can reconstruct the identity after the render-mode switch.
/// </summary>
public sealed class ServerAuthenticationStateProvider : RevalidatingServerAuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentState;
    private readonly PersistingComponentStateSubscription _subscription;
    private Task<AuthenticationState>? _authStateTask;

    protected override TimeSpan RevalidationInterval => TimeSpan.FromMinutes(30);

    public ServerAuthenticationStateProvider(
        ILoggerFactory loggerFactory,
        PersistentComponentState persistentState)
        : base(loggerFactory)
    {
        _persistentState = persistentState;
        AuthenticationStateChanged += OnAuthenticationStateChanged;
        _subscription = _persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    protected override Task<bool> ValidateAuthenticationStateAsync(AuthenticationState authenticationState, CancellationToken cancellationToken)
    {
        return Task.FromResult(true);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
    {
        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, "bob@example.com"),
            new(ClaimTypes.Email, "bob@example.com"),
            new(ClaimTypes.Role, "User"),
            new(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
        var principal = new ClaimsPrincipal(identity);

        return Task.FromResult(new AuthenticationState(principal));
    }

    private void OnAuthenticationStateChanged(Task<AuthenticationState> task)
    {
        _authStateTask = task;
    }

    private async Task OnPersistingAsync()
    {
        var authState = _authStateTask ?? GetAuthenticationStateAsync();
        var state = await authState;
        var principal = state.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var email = principal.FindFirst(ClaimTypes.Email)?.Value ?? "";
            var roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray();

            _persistentState.PersistAsJson(nameof(UserInfo), new UserInfo
            {
                Email = email,
                Roles = roles,
            });
        }
    }

    void IDisposable.Dispose()
    {
        _subscription.Dispose();
        AuthenticationStateChanged -= OnAuthenticationStateChanged;
        base.Dispose();
    }
}

@page "/profile"
@rendermode InteractiveAuto
@using Microsoft.AspNetCore.Components.Authorization
@using System.Security.Claims

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

<AuthorizeView>
    <Authorized>
        <p><strong>Name:</strong> @context.User.Identity?.Name</p>
        <p><strong>Roles:</strong></p>
        <ul>
            @foreach (var role in context.User.FindAll(ClaimTypes.Role))
            {
                <li>@role.Value</li>
            }
        </ul>
    </Authorized>
    <NotAuthorized>
        <p>You are not authenticated.</p>
    </NotAuthorized>
</AuthorizeView>

